from transformers import Qwen3VLForConditionalGeneration, AutoProcessor
import torch
from PIL import Image

model_name = "Qwen/Qwen3-VL-2B-Instruct"
processor = AutoProcessor.from_pretrained(model_name)
model = Qwen3VLForConditionalGeneration.from_pretrained(
    model_name, torch_dtype=torch.float16, device_map="auto"
)

TIER_PROMPTS = {
    "brief": "Describe this image in one short sentence (under 15 words).",
    "standard": "Write an accessibility alt-text in 25-50 words with subjects, actions, and colors.",
    "detailed": "Write a comprehensive 75-150 word description for someone who cannot see this image."
}

def caption_image(image, tier="standard"):
    prompt = TIER_PROMPTS.get(tier, TIER_PROMPTS["standard"])
    messages = [
        {"role": "user", "content": [
            {"type": "image", "image": image},
            {"type": "text", "text": prompt}
        ]}
    ]
    text = processor.apply_chat_template(
        messages, tokenize=False, add_generation_prompt=True
    )
    inputs = processor(
        text=[text], images=[image], return_tensors="pt"
    ).to(model.device)
    output = model.generate(**inputs, max_new_tokens=200, temperature=0.3)
    return processor.decode(
        output[0][inputs["input_ids"].shape[-1]:],
        skip_special_tokens=True
    ).strip()

from pathlib import Path

def batch_caption(image_dir, tier="standard"):
    results = {}
    for img_path in sorted(Path(image_dir).glob("*")):
        if img_path.suffix.lower() in {".jpg", ".jpeg", ".png", ".webp"}:
            image = Image.open(img_path).convert("RGB")
            results[img_path.name] = {
                "caption": caption_image(image, tier),
                "tier": tier
            }
    return results

class AccessibilityCaptionPlugin:
    def __init__(self, caption_fn, tiers):
        self.caption_fn = caption_fn
        self.tiers = tiers

    def alt_text(self, image_path, tier="standard"):
        image = Image.open(image_path).convert("RGB")
        return self.caption_fn(image, tier)

    def all_tiers(self, image_path):
        image = Image.open(image_path).convert("RGB")
        return {t: self.caption_fn(image, t) for t in self.tiers}

    def html_tag(self, image_path, tier="brief"):
        alt = self.alt_text(image_path, tier)
        fname = Path(image_path).name
        return f'<img src="{fname}" alt="{alt}" />'
